practices.bad:
function Table({ rows }: Props) {
  const sorted = rows.sort((a, b) => a.name.localeCompare(b.name));
  return <List items={sorted} />;
}

practices.good:
function Table({ rows }: Props) {
  const sorted = useMemo(() =>
    [...rows].sort((a, b) => a.name.localeCompare(b.name)),
    [rows]
  );
  return <List items={sorted} />;
}
